var e=[{id:`L2_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`하아...... 겨, 경찰 언니......`,JPN:`はあ……け、警察のお姉さん……`,ENG:`*Huff* I-I'm sorry.`,TWN:`哈啊……警、警察姐姐……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`미안해요...... 제가 바보였어요......`,JPN:`ごめんなさい……私は……本当にバカなことを……`,ENG:`I really am. I was a fool.`,TWN:`對不起……我太笨了……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`으으윽...... 아파...... 저 이제...... 죽는 건가요?`,JPN:`ううっ……痛い……私もう……死んじゃうんですか？`,ENG:`Ughhh... It hurts... Am I going to die now?`,TWN:`嗚嗚嗚……痛……我已經……要死了嗎？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`다 죽어가는 소리하지 말고 조금만 버텨.`,JPN:`弱音吐かないでもう少し我慢して。`,ENG:`Stop whining and hang in there.`,TWN:`別說什麼死不死的，再堅持一下。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`우리 강소영 경위가 널 꼭 원래대로 되돌려줄 테니까.`,JPN:`うちのマエカワ警部補がきっと元に戻してくれるから。`,ENG:`Lieutenant Kang here will make sure you get back to normal.`,TWN:`不用擔心……我們的姜素英警衛一定會救妳的。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`그때까지는...... 내가 널 지켜줄게.`,JPN:`それまでは……私が守ってあげる。`,ENG:`And until she does, I'll protect you.`,TWN:`在那之前……我會保護妳。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`고, 고맙......`,JPN:`あ、ありがと……`,ENG:`Th-thank...`,TWN:`謝、謝謝……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`크으윽!!`,JPN:`くううっ！！`,ENG:`Ugh!`,TWN:`唔呃呃！！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`크아아아악!!!!`,JPN:`ぐああああっ！！！！`,ENG:`Graaah!`,TWN:`啊啊啊啊啊！！！！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`강소영 경위! 멀었어? 이성을 거의 잃어가고 있다고!`,JPN:`マエカワ警部補！　まだ？　この子、理性を失いかけてる！`,ENG:`Lieutenant! Are you done? She's losing her mind!`,TWN:`姜素英警衛！還要多久？她幾乎完全失去理性了！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`잠시만요....... 혈액에 잔류하는 엘릭서 성분을 분리해서 융합하면......`,JPN:`待ってください……
血液に残留しているエリクサーの成分を分離して融合させたら……`,ENG:`Hold on... If I can isolate the Elixir molecules in the blood and fuse it...`,TWN:`稍等一下……把在血液裡殘留的聖水成分分離，然後融合的話……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`됐다!`,JPN:`できた！`,ENG:`Done!`,TWN:`好了！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`으으......`,JPN:`あうぅ……`,ENG:`Ugh...`,TWN:`唔……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`성공한 건가?`,JPN:`成功したかな？`,ENG:`Did it work?`,TWN:`成功了嗎？`},stage:{bg:`PRISON_NIGHT`,slots:{L:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L20_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`몸이...... 돌아오고 있어.`,JPN:`体が……元に戻ってる。`,ENG:`Her body... is returning to normal.`,TWN:`身體……正在變回來。`},stage:{bg:`PRISON_NIGHT`,slots:{L:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`아픈게...... `,JPN:`痛みが……`,ENG:`The pain is... `,TWN:`痛苦……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`GIRLSTUDENT_EXTRA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`사라졌어?`,JPN:`消えた？`,ENG:`all gone?`,TWN:`消失了？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`GIRLSTUDENT_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};